import { Injectable, inject, signal, computed } from '@angular/core';
import { MPageService } from '@clinicaloffice/mpage-developer';
import { ConfigurationService } from './configuration.service';
import {
  ALL_TABS,
  TabDefinition,
  AppointmentTypeGroup,
  SuperuserGroupOverride,
  SUPERUSER_OVERRIDE_ALL,
  DEFAULT_LAB_LOOKBACK_HOURS
} from '../models/schedule.model';

export interface ResolvedLabConfig {
  event_set_cd: number;
  lookback_hours: number;
}

@Injectable({ providedIn: 'root' })
export class AccessControlService {
  private readonly mPage = inject(MPageService);
  private readonly configService = inject(ConfigurationService);

  private readonly _positionReady = signal(false);
  private readonly _selectedGroupId = signal<SuperuserGroupOverride>(null);

  readonly userPosition = computed(() => {
    this._positionReady();
    return this.mPage.position ?? '';
  });

  readonly isConfigLoaded = computed(() => this.configService.isLoaded());

  readonly isSuperuser = computed(() => {
    const accessControl = this.configService.configuration()?.ACCESS_CONTROL;
    if (!accessControl) return this.isConfigLoaded();
    return accessControl.superusers.includes(this.userPosition());
  });

  readonly allowedTabs = computed((): TabDefinition[] => {
    const accessControl = this.configService.configuration()?.ACCESS_CONTROL;
    if (!accessControl) return this.isConfigLoaded() ? ALL_TABS : [];
    if (this.isSuperuser()) return ALL_TABS;

    const position = this.userPosition();
    return ALL_TABS.filter(tab => {
      const tabConfig = accessControl.tabs[tab.key];
      return tabConfig?.positions.includes(position) ?? false;
    });
  });

  readonly userGroups = computed<AppointmentTypeGroup[]>(() => {
    const position = this.userPosition();
    if (!position) return [];
    const groups = this.configService.configuration()?.APPOINTMENT_TYPE_GROUPS ?? [];
    return groups.filter(g => g.positions.includes(position));
  });

  readonly hasScheduleAccess = computed<boolean>(
    () => this.isSuperuser() || this.userGroups().length > 0
  );

  readonly availablePickerGroups = computed<AppointmentTypeGroup[]>(() => {
    if (this.isSuperuser()) {
      return this.configService.configuration()?.APPOINTMENT_TYPE_GROUPS ?? [];
    }
    return this.userGroups();
  });

  readonly canPickAllGroups = computed(() => this.isSuperuser());

  readonly shouldShowGroupPicker = computed(() =>
    this.isSuperuser() || this.userGroups().length > 1
  );

  readonly selectedGroupId = this._selectedGroupId.asReadonly();

  readonly effectiveGroupId = computed<string>(() => {
    const sel = this._selectedGroupId();
    const userGrps = this.userGroups();
    const allGroups = this.configService.configuration()?.APPOINTMENT_TYPE_GROUPS ?? [];

    if (this.isSuperuser()) {
      if (sel === SUPERUSER_OVERRIDE_ALL) return SUPERUSER_OVERRIDE_ALL;
      if (sel && allGroups.find(g => g.id === sel)) return sel;
      // Default for superusers is always "All groups"
      return SUPERUSER_OVERRIDE_ALL;
    }

    // Non-superuser
    if (userGrps.length === 0) return '';
    if (sel && sel !== SUPERUSER_OVERRIDE_ALL && userGrps.find(g => g.id === sel)) return sel;
    return userGrps[0].id;
  });

  readonly resolvedAppointmentTypes = computed<number[]>(() => {
    if (!this.hasScheduleAccess()) return [];
    const eff = this.effectiveGroupId();
    if (eff === SUPERUSER_OVERRIDE_ALL) return this.unionOfAllGroups();
    if (!eff) return [];
    const groups = this.configService.configuration()?.APPOINTMENT_TYPE_GROUPS ?? [];
    return groups.find(g => g.id === eff)?.appointment_types ?? [];
  });

  readonly resolvedLabConfig = computed<ResolvedLabConfig | null>(() => {
    const eff = this.effectiveGroupId();
    if (!eff || eff === SUPERUSER_OVERRIDE_ALL) return null;
    const groups = this.configService.configuration()?.APPOINTMENT_TYPE_GROUPS ?? [];
    const grp = groups.find(g => g.id === eff);
    if (!grp || !grp.lab_event_set_cd || grp.lab_event_set_cd <= 0) return null;
    const lookback = grp.lab_lookback_hours && grp.lab_lookback_hours > 0
      ? grp.lab_lookback_hours
      : DEFAULT_LAB_LOOKBACK_HOURS;
    return { event_set_cd: grp.lab_event_set_cd, lookback_hours: lookback };
  });

  readonly activeGroupLabel = computed<string>(() => {
    const eff = this.effectiveGroupId();
    if (eff === SUPERUSER_OVERRIDE_ALL) return 'All groups';
    if (!eff) return '';
    const groups = this.configService.configuration()?.APPOINTMENT_TYPE_GROUPS ?? [];
    return groups.find(g => g.id === eff)?.label ?? '';
  });

  resolvePosition(): void {
    this._positionReady.set(true);
  }

  setSelectedGroupId(value: SuperuserGroupOverride): void {
    this._selectedGroupId.set(value);
  }

  canAccessTab(tabKey: string): boolean {
    const accessControl = this.configService.configuration()?.ACCESS_CONTROL;
    if (!accessControl) return this.isConfigLoaded();
    if (this.isSuperuser()) return true;
    const tabConfig = accessControl.tabs[tabKey];
    return tabConfig?.positions.includes(this.userPosition()) ?? false;
  }

  private unionOfAllGroups(): number[] {
    const groups = this.configService.configuration()?.APPOINTMENT_TYPE_GROUPS ?? [];
    return Array.from(new Set(groups.flatMap(g => g.appointment_types)));
  }
}
